sql.oracle:
CREATE TABLE BPQMLOG_AUDITORIA (
    IDLOG                 NUMBER(15,0)   NOT NULL,
    DTREGISTRO            TIMESTAMP      DEFAULT SYSTIMESTAMP NOT NULL,
    MODULO                VARCHAR2(10)   NOT NULL,
    ENTIDADE              VARCHAR2(50)   NOT NULL,
    IDENTIDADE            NUMBER(15,0)   NOT NULL,
    ACAO                  VARCHAR2(40)   NOT NULL,
    CAMPO_ALTERADO        VARCHAR2(60),
    VALOR_ANTERIOR        VARCHAR2(2000),
    VALOR_NOVO            VARCHAR2(2000),
    DESCRICAO             VARCHAR2(500),
    CODUSU                NUMBER(38,0)   NOT NULL,
    CONSTRAINT PK_BPQM_LOG_AUDITORIA PRIMARY KEY (IDLOG)
);
COMMENT ON TABLE  BPQMLOG_AUDITORIA              IS 'QualityManager: audit log imutavel INSERT ONLY — ISO 9001 clausula 7.5.3';
COMMENT ON COLUMN BPQMLOG_AUDITORIA.MODULO       IS 'NC | FORN | DOC | GM | CORE';
COMMENT ON COLUMN BPQMLOG_AUDITORIA.ENTIDADE     IS 'Nome da tabela afetada. Ex: BPQMNC_REGISTRO';
COMMENT ON COLUMN BPQMLOG_AUDITORIA.ACAO         IS 'INSERT | UPDATE_STATUS | AVANCAR_FASE | CANCELAR | BLOQUEAR | APROVAR';

CREATE OR REPLACE TRIGGER TRG_BPQM_LOG_READONLY
BEFORE UPDATE OR DELETE ON BPQMLOG_AUDITORIA
BEGIN
    RAISE_APPLICATION_ERROR(-20001,
        'BPQMLOG_AUDITORIA e INSERT ONLY. Update e Delete sao proibidos.');
END;

CREATE TABLE BPQMDOM_PRIORIDADE (
    IDPRIORIDADE   NUMBER(10,0)  NOT NULL,
    DESCRICAO      VARCHAR2(50)  NOT NULL,
    PRAZO_DIAS     NUMBER(4),
    ATIVO          CHAR(1)       DEFAULT 'S' NOT NULL,
    CONSTRAINT PK_BPQM_DOM_PRIORIDADE PRIMARY KEY (IDPRIORIDADE),
    CONSTRAINT CK_BPQM_DOM_PRIOR_AT  CHECK (ATIVO IN ('S','N'))
);
COMMENT ON TABLE BPQMDOM_PRIORIDADE IS 'QualityManager: dominio de prioridades — 1=Simples, 2=Prioritario, 3=Critico';

DECLARE v_qtde NUMBER;
BEGIN
    SELECT COUNT(*) INTO v_qtde FROM BPQMDOM_PRIORIDADE;
    IF v_qtde = 0 THEN
        INSERT INTO BPQMDOM_PRIORIDADE (IDPRIORIDADE, DESCRICAO, PRAZO_DIAS) VALUES (1, 'Simples',     30);
        INSERT INTO BPQMDOM_PRIORIDADE (IDPRIORIDADE, DESCRICAO, PRAZO_DIAS) VALUES (2, 'Prioritario', 15);
        INSERT INTO BPQMDOM_PRIORIDADE (IDPRIORIDADE, DESCRICAO, PRAZO_DIAS) VALUES (3, 'Critico',      5);
        COMMIT;
    END IF;
END;

sql.mssql:
DECLARE @qtde INT = 0;
SELECT @qtde = COUNT(*) FROM BPQMDOM_PRIORIDADE;
IF @qtde = 0 BEGIN
    INSERT INTO BPQMDOM_PRIORIDADE (IDPRIORIDADE, DESCRICAO, PRAZO_DIAS) VALUES (1, 'Simples',     30);
    INSERT INTO BPQMDOM_PRIORIDADE (IDPRIORIDADE, DESCRICAO, PRAZO_DIAS) VALUES (2, 'Prioritario', 15);
    INSERT INTO BPQMDOM_PRIORIDADE (IDPRIORIDADE, DESCRICAO, PRAZO_DIAS) VALUES (3, 'Critico',      5);
END;
